class Solution:
    def minimumTime(self, time, totalTrips):
        def trips_by(t):
            return sum(t // x for x in time)

        lo, hi = 1, 1
        while trips_by(hi) < totalTrips:
            hi *= 2
        while lo < hi:
            mid = lo + (hi - lo) // 2
            if trips_by(mid) >= totalTrips:
                hi = mid
            else:
                lo = mid + 1
        return lo

