var minimumTime = function(time, totalTrips) {
    let minT = time[0];
    for (const t of time) if (t < minT) minT = t;
    let lo = 1, hi = minT * totalTrips;
    while (lo < hi) {
        const mid = Math.floor((lo + hi) / 2);
        let trips = 0;
        for (const t of time) trips += Math.floor(mid / t);
        if (trips >= totalTrips) hi = mid;
        else lo = mid + 1;
    }
    return lo;
};
